class Solution:
    def maxFixedPoints(self, nums):
        n = len(nums)
        best = 0
        for mask in range(1 << n):
            kept = [nums[i] for i in range(n) if mask & (1 << i)]
            cnt = sum(1 for idx, v in enumerate(kept) if v == idx)
            if cnt > best:
                best = cnt
        return best

