class Solution:
    def maxFixedPoints(self, nums):
        n = len(nums)
        idxs = [i for i in range(n) if nums[i] <= i]
        m = len(idxs)
        if m == 0:
            return 0
        dp = [1] * m
        best = 1
        for a in range(m):
            i = idxs[a]
            vi = nums[i]
            di = i - vi
            for b in range(a):
                j = idxs[b]
                vj = nums[j]
                if vj < vi and (j - vj) <= di:
                    if dp[b] + 1 > dp[a]:
                        dp[a] = dp[b] + 1
            if dp[a] > best:
                best = dp[a]
        return best

