var maxFixedPoints = function(nums) {
    const n = nums.length;
    const idxs = [];
    for (let i = 0; i < n; i++) {
        if (nums[i] <= i) idxs.push(i);
    }
    const m = idxs.length;
    if (m === 0) return 0;
    const dp = new Array(m).fill(1);
    let best = 1;
    for (let a = 0; a < m; a++) {
        const i = idxs[a];
        const vi = nums[i];
        const di = i - vi;
        for (let b = 0; b < a; b++) {
            const j = idxs[b];
            const vj = nums[j];
            if (vj < vi && (j - vj) <= di) {
                if (dp[b] + 1 > dp[a]) dp[a] = dp[b] + 1;
            }
        }
        if (dp[a] > best) best = dp[a];
    }
    return best;
};
